def process_graph(graph_data):

    graph_copy = graph_data.copy()

    dom_node = None
    for n, data in graph_copy.nodes(data=True):
        if data.get('name') == 'ju1.a3.dom':
            dom_node = n
            break

    new_node = 'new_EK_PACKET_SWITCH_18'
    graph_copy.add_node(new_node, name=new_node, type=['EK_PACKET_SWITCH'])

    if dom_node:
        graph_copy.add_edge(dom_node, new_node, type='RK_CONTAINS')

    count = 0
    if dom_node:
        descendants = nx.descendants(graph_copy, dom_node)
        for n in descendants:
            if 'EK_PACKET_SWITCH' in graph_copy.nodes[n].get('type', []):
                count += 1

    return {"type": "text", "data": str(count), "updated_graph": graph_copy}
